package be.schaubroeck.lpb.rkm.rekenmotor.service;

import be.schaubroeck.lpb.rkm.artikelmotor.ArtikelMotorResultaatHandler;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.results.ResultaatHandler;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RegulManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenFeedback;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.ArtikelHoofd;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.util.InitializeAdmin;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;

@Transactional
public class ResultaatHandlerServiceImp implements ResultaatHandlerService {

    @Override
    @InitializeAdmin
    public void verwerkResultaten(Admin admin, ResultaatHandler handler, RekenContext mainContext) {
        handler.verwerkResultaten(admin, mainContext);
    }

    @Override
    @InitializeAdmin
    public void verwerkReguls(Admin admin, ResultaatHandler handler, RekenContext mainContext, boolean stopState) {
        handler.verwerkReguls(admin, mainContext, stopState);
    }

    @Override
    @InitializeAdmin
    public void verwerkReguls(
            Admin admin, ArtikelMotorResultaatHandler handler, RekenTijd rekenTijd, Persoon persoon, RegulManager regulManager,
            RekenFeedback feedback, boolean stopState) {
        handler.verwerkReguls(admin, rekenTijd, persoon, regulManager, feedback, stopState);
    }

    @Override
    @InitializeAdmin
    public void verwerkArtikelResultaten(
            Admin admin, ArtikelMotorResultaatHandler handler, RekenTijd rekenTijd, List<ArtikelHoofd> nieuweBoekingen,
            RekenFeedback feedback) {
        handler.verwerkResultaten(admin, rekenTijd, nieuweBoekingen, feedback);
    }

    @Override
    @InitializeAdmin
    public void cleanResultaten(Admin admin, ResultaatHandler handler, RekenContext mainContext) {
        handler.cleanResultaten(admin, mainContext);
    }

}
